css:
/* Retourenschein — A4, eine Seite. Oben Schnitt-Streifen mit Rücksende-
   Adresse, dann Items-Tabelle, Gründe-Liste, IBAN-Feld, Unterschriften
   und ein "Vom Lager auszufüllen"-Block. */

.sr-only {
  position: absolute;
  width: 1px; height: 1px;
  overflow: hidden;
  clip: rect(0 0 0 0);
}

/* Abtrenn-Streifen oben — Rücksende-Label das auf das Paket geklebt
   wird. Border auf 3 Seiten + dashed unten als Schnittlinie. */
.rt-cut {
  display: grid;
  grid-template-columns: 1fr 60mm;
  gap: 6mm;
  align-items: center;
  padding: 5mm 6mm;
  border: 0.3mm solid #111827;
  margin-bottom: 0;
}
.rt-cut__title {
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.4px;
  font-weight: 700;
  color: #6b7280;
  margin-bottom: 2mm;
}
.rt-cut__addr {
  font-size: 11pt;
  line-height: 1.35;
}
.rt-cut__barcode { text-align: center; }
.rt-cut__barcode-caption {
  font-family: monospace;
  font-size: 9pt;
  margin-top: 1mm;
  letter-spacing: 0.3pt;
}

.rt-cut-marker {
  text-align: center;
  font-size: 8pt;
  color: #6b7280;
  letter-spacing: 1pt;
  padding: 3mm 0 8mm;
  border-top: 0.3mm dashed #9ca3af;
  border-bottom: 0.3mm dashed #9ca3af;
  margin-bottom: 6mm;
}

/* RMA-Barcode oben rechts im Schnitt-Block — Code-128-Style. */
.barcode-rma {
  height: 12mm;
  background:
    repeating-linear-gradient(
      to right,
      #111827 0 0.5mm,
      transparent 0.5mm 0.9mm,
      #111827 0.9mm 1.2mm,
      transparent 1.2mm 1.8mm,
      #111827 1.8mm 2.3mm,
      transparent 2.3mm 2.9mm,
      #111827 2.9mm 3.2mm,
      transparent 3.2mm 4mm
    );
  border-bottom: 0.2mm solid #111827;
}

.rt-intro {
  font-size: 10pt;
  color: #4b5563;
  margin: 1mm 0 0;
  line-height: 1.45;
}

.rt-meta { margin: 4mm 0 6mm; }
.rt-meta dl {
  display: grid;
  grid-template-columns: max-content 1fr max-content 1fr;
  gap: 1mm 4mm;
  margin: 0;
  font-size: 9.5pt;
}
.rt-meta dl > div { display: contents; }
.rt-meta dt {
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  font-weight: 700;
  color: #6b7280;
}
.rt-meta dd { margin: 0; }
.rt-meta__group { grid-column: 1 / -1; }

.rt-card {
  margin: 4mm 0 6mm;
  padding: 3mm 5mm;
  background: rgba(15,23,42,0.03);
  border-radius: 1.5mm;
}
.rt-card__title {
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  font-weight: 700;
  color: #6b7280;
  margin: 0 0 1mm;
}
.rt-card__body {
  margin: 0;
  font-size: 10pt;
  line-height: 1.4;
}

.rt-section-title {
  font-size: 10pt;
  font-weight: 700;
  margin: 4mm 0 2mm;
  color: #111827;
}

.rt-items {
  width: 100%;
  border-collapse: collapse;
  font-size: 9.5pt;
}
.rt-items thead th {
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  text-align: left;
  background: #f3f4f6;
  border-bottom: 0.4mm solid #6b7280;
  padding: 2mm 3mm;
  color: #374151;
}
.rt-items tbody td {
  padding: 2.5mm 3mm;
  border-bottom: 0.2mm solid #e5e7eb;
  vertical-align: middle;
}
.rt-items__col-pos    { width: 10mm; color: #6b7280; }
.rt-items__col-sku    { width: 26mm; font-family: monospace; }
.rt-items__col-qty    { width: 22mm; text-align: right; font-variant-numeric: tabular-nums; }
.rt-items__col-ret    { width: 22mm; text-align: center; }
.rt-items__col-reason { width: 22mm; text-align: center; }
.rt-items__ean {
  font-size: 8pt;
  color: #6b7280;
}

.rt-input {
  display: inline-block;
  height: 6mm;
  border-bottom: 0.3mm solid #111827;
}
.rt-input--qty    { width: 14mm; }
.rt-input--reason { width: 14mm; }

.rt-reasons {
  margin: 6mm 0;
  padding: 4mm 5mm;
  border: 0.3mm solid #d1d5db;
  border-radius: 1.5mm;
}
.rt-reasons__list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1.5mm 6mm;
}
.rt-reasons__list li {
  display: flex;
  align-items: center;
  gap: 2.5mm;
  font-size: 9.5pt;
}
.rt-reasons__code {
  font-family: monospace;
  font-weight: 700;
  font-size: 8.5pt;
  color: #4b5563;
}
.rt-reasons__other {
  margin-top: 4mm;
}
.rt-reasons__other-label {
  font-size: 8.5pt;
  font-weight: 600;
  color: #4b5563;
  margin-bottom: 1mm;
}
.rt-reasons__other-box {
  height: 16mm;
  border: 0.2mm solid #d1d5db;
  border-radius: 1mm;
}

.rt-refund {
  margin: 6mm 0;
  padding: 4mm 5mm;
  background: rgba(109, 124, 255, 0.06);
  border-radius: 1.5mm;
}
.rt-refund__default {
  margin: 0 0 2mm;
  font-size: 9.5pt;
  color: #1f2937;
}
.rt-refund__iban {
  font-size: 9.5pt;
}
.rt-refund__iban-label {
  font-weight: 600;
  margin-right: 2mm;
}
.rt-refund__iban-box {
  display: inline-block;
  min-width: 110mm;
  height: 6mm;
  border-bottom: 0.3mm solid #111827;
  font-family: monospace;
}

.rt-signature {
  margin: 6mm 0;
}
.rt-signature__row {
  display: grid;
  grid-template-columns: 60mm 1fr;
  gap: 10mm;
}
.rt-signature__line {
  border-bottom: 0.3mm solid #111827;
  height: 12mm;
}
.rt-signature__label {
  font-size: 9pt;
  color: #6b7280;
  margin-top: 1mm;
}

.rt-checkbox {
  display: inline-block;
  width: 4.5mm;
  height: 4.5mm;
  border: 0.4mm solid #111827;
  border-radius: 0.5mm;
  vertical-align: middle;
  flex-shrink: 0;
}

.rt-office {
  margin-top: 8mm;
  padding: 4mm 5mm;
  border: 0.3mm dashed #9ca3af;
  border-radius: 1.5mm;
  background: rgba(15,23,42,0.02);
  page-break-inside: avoid;
}
.rt-office__title {
  margin: 0 0 3mm;
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  font-weight: 700;
  color: #6b7280;
}
.rt-office__grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4mm 8mm;
}
.rt-office__label {
  font-size: 8.5pt;
  font-weight: 600;
  color: #4b5563;
  margin-bottom: 1mm;
}
.rt-office__line {
  border-bottom: 0.3mm solid #6b7280;
  height: 7mm;
}
.rt-office__pills {
  display: flex;
  gap: 4mm;
  flex-wrap: wrap;
  font-size: 9pt;
}
.rt-office__pills span {
  display: inline-flex;
  align-items: center;
  gap: 2mm;
}
